const MOON_IN_HOUSE = {"1":"Bạn tìm an toàn qua hình ảnh bản thân, phản ứng cảm xúc và cách mọi người nhìn nhận bạn.","2":"Bạn tìm cảm xúc vững qua tiền bạc, tài sản và cảm giác đủ đầy vật chất.","3":"Bạn tìm an toàn qua lời nói, học hỏi hàng ngày và kết nối với anh chị em.","4":"Bạn tìm cảm xúc ấm áp qua gia đình, quê hương và không gian riêng tư thân thuộc.","5":"Bạn tìm an toàn qua sáng tạo, tình yêu vui vẻ và niềm vui với con cái.","6":"Bạn tìm cảm xúc ổn định qua thói quen, công việc hàng ngày và chăm sóc sức khỏe.","7":"Bạn tìm an toàn qua mối quan hệ gần gũi, hôn nhân và sự đồng hành của đối tác.","8":"Bạn tìm cảm xúc sâu qua chia sẻ tài sản, biến đổi nội tâm và gắn kết mật thiết.","9":"Bạn tìm an toàn qua triết lý sống, hành trình xa và niềm tin tinh thần rộng mở.","10":"Bạn tìm cảm xúc vững qua sự nghiệp, danh tiếng và vị trí được xã hội công nhận.","11":"Bạn tìm an toàn qua bạn bè, cộng đồng và lý tưởng chung mang lại thuộc về.","12":"Bạn tìm cảm xúc qua tĩnh lặng, thế giới nội tâm và những gì ẩn giấu sâu kín."};
const VENUS_IN_HOUSE = {"1":"Venus nơi đây làm bạn toát vẻ duyên dáng, dễ mến và thu hút bằng chính phong thái riêng.","2":"Bạn yêu cái đẹp qua vật chất, kiếm tiền bằng gu thẩm mỹ và biết trân trọng giá trị.","3":"Lời nói ngọt ngào, thích giao lưu nhẹ nhàng; tình cảm nảy nở qua trò chuyện gần gũi.","4":"Bạn tìm bình yên trong tổ ấm, yêu không gian đẹp và gắn bó sâu với gia đình.","5":"Tình yêu rực rỡ, thích tán tỉnh, nghệ thuật và niềm vui; con cái thường mang nhiều ân sủng.","6":"Bạn yêu qua phục vụ tinh tế, cần môi trường làm việc hài hòa để giữ sức khỏe.","7":"Hôn nhân và đối tác là trọng tâm; bạn khao khát tình yêu công bằng, hài hòa.","8":"Tình cảm sâu, mãnh liệt; sắc đẹp và tiền chung, kế thừa gắn với biến đổi nội tâm.","9":"Bạn si mê qua tri thức, du lịch, văn hóa xa; tình yêu mang màu lý tưởng cao.","10":"Vẻ duyên dáng giúp thăng tiến; sự nghiệp gắn nghệ thuật, quan hệ công chúng và hình ảnh đẹp.","11":"Bạn tìm tình trong hội nhóm, bạn bè thân; lý tưởng chung nuôi dưỡng cảm xúc ấm áp.","12":"Tình yêu thầm lặng, hy sinh hoặc bí ẩn; cái đẹp chạm sâu tầng vô thức và tâm linh."};
const MARS_IN_HOUSE = {"1":"Bạn hành động quyết liệt, dám xông pha, khẳng định bản thân bằng năng lượng thô và dũng khí.","2":"Bạn đổ sức tranh thủ tài chính, kiếm tiền quyết liệt, bảo vệ của cải bằng hành động.","3":"Lời nói sắc bén, tranh luận nhiệt tình, học hỏi nhanh và chủ động kết nối xung quanh.","4":"Năng lượng dồn vào nhà cửa, bảo vệ gia đình, đôi khi căng thẳng trong không gian riêng.","5":"Đam mê sáng tạo bùng nổ, yêu mạnh, chơi hết mình, dẫn dắt con cái quyết liệt.","6":"Làm việc hăng say, cạnh tranh nơi bàn làm, cần kiểm soát stress và sức khỏe.","7":"Quan hệ sôi động, đối đầu rồi hòa, bạn chủ động dẫn dắt và thúc đẩy đối tác.","8":"Bạn xông vào khủng hoảng, biến đổi sâu, xử lý tiền chung và sức mạnh ẩn.","9":"Hành trình xa, tranh biện niềm tin, học hỏi quyết liệt, mở rộng chân trời bằng dũng khí.","10":"Tham vọng nghề nghiệp mạnh, dám dẫn dắt, tranh đua địa vị và khẳng định danh tiếng.","11":"Năng lượng cho nhóm, lý tưởng, mạng lưới; bạn thúc đẩy bạn bè và mục tiêu chung.","12":"Hành động ngầm, nội chiến tâm lý; năng lượng ẩn cần được giải phóng có ý thức."};
const ASPECT_MEANINGS = {"Hợp nhất":"Hai hành tinh hòa thành một năng lượng chung, tăng cường lẫn nhau và tạo dấu ấn mạnh trong bản đồ sao. Tài năng nổi bật khi hai hành tinh hỗ trợ; cảnh báo khi một hành tinh “nuốt” ý chí của hành tinh kia, dễ mất cân bằng.","Đối xung":"Hai lực đối lập kéo căng, buộc bạn thấy hai mặt của cùng một vấn đề. Tài năng nằm ở khả năng hòa giải và nhìn toàn cục; cảnh báo là phân cực, đổ lỗi bên ngoài hoặc dao động cực đoan.","Tam hợp":"Dòng chảy thuận, năng lượng hai hành tinh hợp tác dễ dàng, mang ơn phước tự nhiên. Tài năng phát huy mượt mà; cảnh báo là dễ ỷ lại, lười rèn luyện vì “mọi thứ vốn suôn sẻ”.","Vuông góc":"Xung đột nội tại tạo ma sát, thúc đẩy hành động và trưởng thành. Tài năng hình thành qua thử thách và kỷ luật; cảnh báo là căng thẳng, nóng vội, tự phá hoặc cứng đầu.","Lục hợp":"Cơ hội êm dịu, cần chủ động nắm bắt mới thành kết quả. Tài năng nằm ở linh hoạt và hợp tác đúng lúc; cảnh báo là bỏ lỡ nếu ngồi chờ “tự đến”."};
const ASPECT_PAIRS = {"Sun-Moon":"Tam hợp = bản ngã và cảm xúc đồng điệu, dễ tự tin ổn định; vuông/đối = mâu thuẫn muốn gì vs cần gì, dao động tâm trạng.","Sun-Venus":"Tam hợp = duyên dáng, hài hòa trong tình cảm và thẩm mỹ; vuông/đối = thích thú lệch với giá trị bản thân, dễ chiều lòng hoặc tự ái.","Sun-Mars":"Tam hợp = ý chí và hành động thống nhất, dám làm dám chịu; vuông/đối = nóng nảy, cạnh tranh quá mức, dễ xung đột.","Sun-Saturn":"Tam hợp = trách nhiệm, bền bỉ, thành tựu lâu dài; vuông/đối = tự hạn chế, áp lực, sợ thất bại hoặc nghiêm khắc với mình.","Moon-Venus":"Tam hợp = ấm áp, dễ yêu và được yêu, nhu cầu tình cảm êm; vuông/đối = phụ thuộc cảm xúc, khó hài lòng hoặc dễ tổn thương.","Venus-Mars":"Tam hợp = hấp dẫn, tình dục–tình cảm cân bằng, nhiệt tình dễ chịu; vuông/đối = căng thẳng dục vọng vs tình cảm, dễ ghen hoặc xung đột tình ái.","Venus-Saturn":"Tam hợp = tình yêu trưởng thành, trung thành, giá trị bền; vuông/đối = rào cản tình cảm, sợ gần gũi, hoặc đánh đổi yêu thương vì nghĩa vụ.","Mars-Saturn":"Tam hợp = sức bền, kỷ luật hành động, chiến thắng dài hơi; vuông/đối = ức chế, bực bội, khởi đầu khó hoặc kiệt sức vì ép mình."};
const ELEMENT_BALANCE = {"Hỏa trội":"Nhiệt huyết, dũng cảm, thích hành động và dẫn dắt; dễ bốc đồng, thiếu kiên nhẫn nếu không được kiềm chế.","Thổ trội":"Thực tế, kiên định, coi trọng an toàn và kết quả cụ thể; đôi khi cứng nhắc, chậm thay đổi.","Khí trội":"Lý trí, giao tiếp tốt, thích học hỏi và kết nối ý tưởng; dễ lo âu, phân tán, sống xúc hời hợt.","Thủy trội":"Nhạy cảm, trực giác mạnh, giàu đồng cảm và đời sống nội tâm; dễ bị cuốn theo cảm xúc, khó rạch ròi.","Thiếu Hỏa":"Thiếu động lực và tự tin khởi sự; cần chủ động thắp nhiệt huyết, tránh thụ động chờ đợi.","Thiếu Thổ":"Khó bám thực tế, thiếu kiên trì hoàn tất; cần kỷ luật, kế hoạch và nền tảng ổn định hơn.","Thiếu Khí":"Khó diễn đạt, ít linh hoạt trong tư duy; cần mở rộng giao tiếp và nhìn vấn đề đa chiều.","Thiếu Thủy":"Ít nhạy cảm với cảm xúc bản thân và người khác; cần nuôi dưỡng sự lắng nghe và đồng cảm.","Khởi đầu trội":"Giỏi mở đầu, dẫn dắt, thích tạo động lực mới; dễ bỏ dở giữa chừng nếu thiếu người theo sát.","Cố định trội":"Bền bỉ, trung thành, giữ vững mục tiêu; dễ bảo thủ, ngại thay đổi khi hoàn cảnh đòi hỏi.","Linh hoạt trội":"Thích nghi nhanh, đa năng, dễ điều chỉnh; dễ phân tán, thiếu quyết đoán và khó chốt định."};
